import '../../domain/entities/security_entity.dart'; class SecurityEventModel extends SecurityEventEntity { const SecurityEventModel({required super.eventId, required super.type, required super.level, required super.description, required super.deviceId, required super.timestamp}); factory SecurityEventModel.fromJson(Map<String, dynamic> j) => SecurityEventModel(eventId: j['eventId'] ?? '', type: SecurityEventType.values.firstWhere((t) => t.name == j['type'], orElse: () => SecurityEventType.suspiciousActivity), level: SecurityLevel.values.firstWhere((l) => l.name == j['level'], orElse: () => SecurityLevel.low), description: j['description'] ?? '', deviceId: j['deviceId'] ?? '', timestamp: j['timestamp'] != null ? DateTime.fromMillisecondsSinceEpoch(j['timestamp'] as int) : DateTime.now()); Map<String, dynamic> toJson() => {'eventId': eventId, 'type': type.name, 'level': level.name, 'description': description, 'deviceId': deviceId, 'timestamp': timestamp.millisecondsSinceEpoch}; }
